using Microsoft.ML;
using Microsoft.ML.Data;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public class TicketClassifierService
{
    private readonly MLContext _mlContext;
    private ITransformer? _model;
    private PredictionEngine<TicketData, TicketPrediction>? _predictionEngine;
    private readonly string _dataPath;
    private readonly string _modelPath;
    private string[] _categoryNames = [];
    private readonly object _lock = new();

    public bool IsModelTrained => _model is not null;

    public TicketClassifierService(IWebHostEnvironment env)
    {
        _mlContext = new MLContext(seed: 42);
        _dataPath = Path.Combine(env.ContentRootPath, "Data", "tickets.csv");
        _modelPath = Path.Combine(env.ContentRootPath, "Data", "model.zip");
    }

    public TrainingResult TrainAndEvaluate()
    {
        var dataView = _mlContext.Data.LoadFromTextFile<TicketData>(
            _dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        // Build the training pipeline
        var pipeline = _mlContext.Transforms.Conversion.MapValueToKey("Label")
            .Append(_mlContext.Transforms.Text.FeaturizeText("SubjectFeaturized", nameof(TicketData.Subject)))
            .Append(_mlContext.Transforms.Text.FeaturizeText("DescriptionFeaturized", nameof(TicketData.Description)))
            .Append(_mlContext.Transforms.Concatenate("Features",
                "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketData.Priority)))
            .Append(_mlContext.Transforms.NormalizeMinMax("Features"))
            .AppendCacheCheckpoint(_mlContext)
            .Append(_mlContext.MulticlassClassification.Trainers.SdcaMaximumEntropy(
                labelColumnName: "Label", featureColumnName: "Features"))
            .Append(_mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));

        // Use cross-validation for evaluation since the dataset is small
        var cvResults = _mlContext.MulticlassClassification.CrossValidate(dataView, pipeline, numberOfFolds: 3);

        // Train the final model on all data
        lock (_lock)
        {
            _model = pipeline.Fit(dataView);
            _predictionEngine = _mlContext.Model.CreatePredictionEngine<TicketData, TicketPrediction>(_model);

            // Extract category names from the key mapping
            var labelColumn = dataView.Schema["Label"];
            var keyValues = new VBuffer<ReadOnlyMemory<char>>();
            _model.GetOutputSchema(dataView.Schema)["Label"]
                .GetKeyValues(ref keyValues);
            _categoryNames = keyValues.DenseValues().Select(v => v.ToString()).ToArray();

            // Save model
            _mlContext.Model.Save(_model, dataView.Schema, _modelPath);
        }

        // Average CV metrics
        var avgMetrics = new EvaluationMetrics
        {
            MacroAccuracy = cvResults.Average(r => r.Metrics.MacroAccuracy),
            MicroAccuracy = cvResults.Average(r => r.Metrics.MicroAccuracy),
            LogLoss = cvResults.Average(r => r.Metrics.LogLoss),
            LogLossReduction = cvResults.Average(r => r.Metrics.LogLossReduction),
            PerCategoryMetrics = BuildPerCategoryMetrics(cvResults)
        };

        return new TrainingResult
        {
            Status = "Model trained successfully",
            Metrics = avgMetrics
        };
    }

    public PredictionResult Predict(TicketRequest request)
    {
        lock (_lock)
        {
            if (_predictionEngine is null)
                throw new InvalidOperationException("Model has not been trained. Call POST /api/tickets/train first.");

            var input = new TicketData
            {
                Subject = request.Subject,
                Description = request.Description,
                Priority = request.Priority
            };

            var prediction = _predictionEngine.Predict(input);

            var confidence = new Dictionary<string, float>();
            for (int i = 0; i < _categoryNames.Length && i < prediction.Score.Length; i++)
            {
                confidence[_categoryNames[i]] = prediction.Score[i];
            }

            return new PredictionResult
            {
                PredictedCategory = prediction.Category,
                Confidence = confidence
            };
        }
    }

    private List<CategoryMetric> BuildPerCategoryMetrics(
        IReadOnlyList<CrossValidationResult<MulticlassClassificationMetrics>> cvResults)
    {
        var metrics = new List<CategoryMetric>();
        var first = cvResults.FirstOrDefault()?.Metrics.PerClassLogLoss;
        if (first is null) return metrics;

        for (int i = 0; i < first.Count && i < _categoryNames.Length; i++)
        {
            int idx = i;
            metrics.Add(new CategoryMetric
            {
                Category = _categoryNames[idx],
                Precision = cvResults.Average(r =>
                    idx < r.Metrics.ConfusionMatrix.PerClassPrecision.Count
                        ? r.Metrics.ConfusionMatrix.PerClassPrecision[idx] : 0),
                Recall = cvResults.Average(r =>
                    idx < r.Metrics.ConfusionMatrix.PerClassRecall.Count
                        ? r.Metrics.ConfusionMatrix.PerClassRecall[idx] : 0),
                F1Score = ComputeF1(
                    cvResults.Average(r =>
                        idx < r.Metrics.ConfusionMatrix.PerClassPrecision.Count
                            ? r.Metrics.ConfusionMatrix.PerClassPrecision[idx] : 0),
                    cvResults.Average(r =>
                        idx < r.Metrics.ConfusionMatrix.PerClassRecall.Count
                            ? r.Metrics.ConfusionMatrix.PerClassRecall[idx] : 0))
            });
        }

        return metrics;
    }

    private static double ComputeF1(double precision, double recall)
    {
        if (precision + recall == 0) return 0;
        return 2 * precision * recall / (precision + recall);
    }
}

